sql:
SELECT region, SUM(registered_voters) AS total_registered_voters
FROM authorities
GROUP BY region;

SELECT registered_voters
FROM authorities
WHERE authority_name = 'Orkney';

external_knowledge:
- Authority types include 'National' and 'Local'; 
- Voter turnout percentage refers to the percentage of registered voters who participated in the election; 
- Cumulative voter turnout percentage refers to the running total of average voter turnout percentages for authorities in a region, ordered by type.

sql:
SELECT authority_name
FROM authorities
ORDER BY authority_name ASC;

SELECT authority_name, registered_voters
FROM authorities
ORDER BY registered_voters DESC;
